const job = $input.first().json;

// In a real scenario, this would query a Company Enrichment API (like Clearbit, Apollo, or LinkedIn) 
// based on `job.company_name` to find industry, funding, and size.

// For Phase 4 Mock, we do deterministic inference based on name length/keywords.
let size = 'unknown';
let industry = 'Technology';

const name = (job.company_name || '').toLowerCase();
if (name.includes('inc') || name.includes('corp')) size = '1000+';
else if (name.includes('llc') || name.includes('group')) size = '200-1000';
else size = '1-50';

if (name.includes('health') || name.includes('med')) industry = 'Healthcare';
else if (name.includes('bank') || name.includes('capital')) industry = 'Finance';

job.enrichment = job.enrichment || {};
job.enrichment.company_size = size;
job.enrichment.industry = industry;

return [{ json: job }];
